#include <iostream>
#include <vector>
#include <deque>

class Node {
public:
    int value;
    Node* next;
    Node* prev;

    Node(int value = 0) : value(value), next(nullptr), prev(nullptr) {}
};

class Solution {
public:
    std::deque<Node*> queue;

    bool isEmpty() {
        return queue.empty();
    }

    void removeFront() {
        if (isEmpty()) return;
        Node* node = queue.front();
        queue.pop_front();
        delete node;
    }

    void solve() {
        for (int i = 1; i <= 5; ++i) {
            Node* node = new Node(i);
            queue.push_back(node);
        }

        removeFront();

        for (const auto& node : queue) {
            std::cout << node->value << ' ';
        }
    }
};

int main() {
    Solution solution;
    solution.solve();

    return 0;
}
